module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);


reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= s0;
    end else begin
        case (state)
            s0: begin
                if (data_in == 1'b0) state <= s1; else state <= s0;
            end
            s1: begin
                if (data_in == 1'b1) state <= s2; else state <= s1;
            end
            s2: begin
                if (data_in == 1'b0) state <= s3; else state <= s0;
            end
            s3: begin
                if (data_in == 1'b1) state <= s2; else state <= s1;
            end
        endcase
    end
end

always @(*) begin
    case (state)
        s0: data_out = 1'b0;
        s1: data_out = 1'b0;
        s2: data_out = (data_in == 1'b0);
        s3: data_out = 1'b0;
    endcase
end
endmodule
